namespace sv_516ffd41bdc44f0a9c9fe06cb5650c3c;

public enum Theme
{
    Light,
    Dark,
    System
}

public class ThemeInfo
{
    public Theme Theme { get; set; } = Theme.Light;
    public string AccentColor { get; set; } = "#0d6efd";
}

@rendermode InteractiveServer

<span class="badge" style="background-color: @(Theme?.AccentColor ?? "#0d6efd")">
    @(Theme?.Theme.ToString() ?? "Light")
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }
}

@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card p-4" style="max-width: 400px;">
    <div class="mb-3">
        <label class="form-label fw-bold">Theme</label>
        <select class="form-select" value="@currentTheme" @onchange="OnThemeChanged">
            @foreach (var t in Enum.GetValues<Theme>())
            {
                <option value="@t">@t</option>
            }
        </select>
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Accent Color</label>
        <input type="color" class="form-control form-control-color"
               value="@currentAccent" @onchange="OnAccentChanged" />
    </div>

    <p class="text-muted small mt-2">
        Current: <strong>@ThemeState?.Theme</strong> /
        <span style="color: @(ThemeState?.AccentColor)">@ThemeState?.AccentColor</span>
    </p>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? ThemeState { get; set; }

    @inject CascadingValueSource<ThemeInfo> ThemeSource

    private string currentTheme = Theme.Light.ToString();
    private string currentAccent = "#0d6efd";

    protected override void OnParametersSet()
    {
        if (ThemeState is not null)
        {
            currentTheme = ThemeState.Theme.ToString();
            currentAccent = ThemeState.AccentColor;
        }
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var parsed))
        {
            var updated = new ThemeInfo
            {
                Theme = parsed,
                AccentColor = ThemeState?.AccentColor ?? currentAccent
            };
            await ThemeSource.NotifyChangedAsync(updated);
        }
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        var updated = new ThemeInfo
        {
            Theme = ThemeState?.Theme ?? Theme.Light,
            AccentColor = e.Value?.ToString() ?? "#0d6efd"
        };
        await ThemeSource.NotifyChangedAsync(updated);
    }
}

